import { useQuery, useAction, getTasks, createTask, updateTask } from 'wasp/client/operations';
import { logout } from 'wasp/client/auth';
import { AuthUser } from 'wasp/auth';

export const MainPage = ({ user }: { user: AuthUser }) => {
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const createTaskAction = useAction(createTask);
  const updateTaskAction = useAction(updateTask);

  const handleSubmit = async (event: any) => {
    event.preventDefault();
    try {
      const description = event.target.description.value;
      event.target.reset();
      await createTaskAction({ description });
    } catch (err: any) {
      window.alert('Error: ' + err.message);
    }
  };

  const handleToggle = async (task: any) => {
    try {
      await updateTaskAction({ id: task.id, isDone: !task.isDone });
    } catch (err: any) {
      window.alert('Error: ' + err.message);
    }
  };

  if (isLoading) return 'Loading...';
  if (error) return 'Error: ' + (error as any).message;

  return (
    <div style={{ padding: '20px', maxWidth: '600px', margin: 'auto' }}>
      <h1>{user.id}'s Todo List</h1>
      <button onClick={logout}>Logout</button>
      <hr />
      <form onSubmit={handleSubmit} style={{ marginBottom: '20px' }}>
        <input name="description" placeholder="What needs to be done?" required style={{ marginRight: '10px' }} />
        <button type="submit">Add Task</button>
      </form>
      <ul style={{ listStyleType: 'none', padding: 0 }}>
        {tasks?.map((task) => (
          <li key={task.id} style={{ display: 'flex', alignItems: 'center', marginBottom: '10px' }}>
            <input
              type="checkbox"
              checked={task.isDone}
              onChange={() => handleToggle(task)}
              style={{ marginRight: '10px' }}
            />
            <span style={{ textDecoration: task.isDone ? 'line-through' : 'none' }}>
              {task.description}
            </span>
          </li>
        ))}
      </ul>
    </div>
  );
};

