import { Task } from 'wasp/entities';
import { type CreateTask, type UpdateTask } from 'wasp/server/operations';
import { HttpError } from 'wasp/server';

type CreateTaskArgs = {
  description: string;
};

export const createTask: CreateTask<CreateTaskArgs, Task> = async (args, context) => {
  if (!context.user) {
    throw new HttpError(401);
  }
  return context.entities.Task.create({
    data: {
      description: args.description,
      user: { connect: { id: context.user.id } },
    },
  });
};

type UpdateTaskArgs = {
  id: number;
  isDone: boolean;
};

export const updateTask: UpdateTask<UpdateTaskArgs, Task> = async (args, context) => {
  if (!context.user) {
    throw new HttpError(401);
  }
  return context.entities.Task.update({
    where: { id: args.id, userId: context.user.id },
    data: { isDone: args.isDone },
  });
};

